import warnings
from typing import Literal, Tuple, Union, overload

import numpy as np


def pca(
    data: np.ndarray, correlation: bool = False, sort: bool = True
) -> Tuple[np.ndarray, np.ndarray]:
    """Applies Principal Component Analysis to the data

    :param data: The array containing the data. The array must have NxM dimensions,
        where each of the N rows represents a different individual record and each
        of the M columns represents a different variable recorded for that
        individual record.

        Expected format::

            array([
                [V11, ... , V1m],
                ...,
                [Vn1, ... , Vnm]
            ])

    :param correlation: Set the type of matrix to be computed (see Notes):
        If ``True`` compute the correlation matrix.
        If ``False`` compute the covariance matrix.

    :param sort: Set the order that the eigenvalues/vectors will have
        If ``True`` they will be sorted (from higher value to less).
        If ``False`` they won't.
    :return: eigenvalues ``(1, M)``, eigenvector ``(M, M)``:
        The eigenvalues and the eigenvectors of the corresponding matrix.


    .. note::
        The correlation matrix is a better choice when there are different magnitudes
        representing the M variables. Use covariance matrix in other cases.

    """

    mean = np.mean(data, axis=0)

    data_adjust = data - mean

    #: the data is transposed due to np.cov/corrcoef syntax
    if correlation:
        matrix = np.corrcoef(data_adjust.T)

    else:
        matrix = np.cov(data_adjust.T)

    eigenvalues, eigenvectors = np.linalg.eig(matrix)

    if sort:
        #: sort eigenvalues and eigenvectors
        indices = np.argsort(-eigenvalues)
        eigenvalues = eigenvalues[indices]
        eigenvectors = eigenvectors[:, indices]

    return eigenvalues, eigenvectors


def _compute_mean_and_normal(points: np.ndarray) -> Tuple[np.ndarray, np.ndarray]:
    w, v = pca(points)
    #: the normal of the plane is the last eigenvector
    normal = v[:, 2]
    #: get a point from the plane
    point = np.mean(points, axis=0)
    return point, normal


def compute_best_fitting_plane(points: np.ndarray) -> Tuple[float, float, float, float]:
    """Computes the best fitting plane of the given points

    :param points: The x, y, z coordinates corresponding to the points from which
        we want to define the best fitting plane.

        Expected format::

            array([
               [x1, y1, z1],
               ...,
               [xn, yn, zn]
            ])

    :return: The coefficients solving the plane equation ``ax + by + cz + d = 0``
    """
    point, normal = _compute_mean_and_normal(points)
    a, b, c = normal
    d = -(np.dot(normal, point))
    return a, b, c, d


@overload
def best_fitting_plane(
    points: np.ndarray, equation: Literal[True] = True
) -> Tuple[float, float, float, float]: ...


@overload
def best_fitting_plane(
    points: np.ndarray, equation: Literal[False]
) -> Tuple[np.ndarray, np.ndarray]: ...


def best_fitting_plane(
    points: np.ndarray, equation: bool = True
) -> Union[Tuple[np.ndarray, np.ndarray], Tuple[float, float, float, float]]:
    """Computes the best fitting plane of the given points

    :param points: The x, y, z coordinates corresponding to the points from which
        we want to define the best fitting plane.

        Expected format::

            array([
               [x1, y1, z1],
               ...,
               [xn, yn, zn]
            ])

    :param equation: Set the output plane format:

        - If ``True`` return the a, b, c and d coefficients of the plane.

        - If ``False`` return one point and one normal vector.

    :returns: Either of these objects:

        - ``(a, b, c, d)``: The coefficients solving the plane equation.
          ``ax + by + cz + d = 0``,

        - ``(point, normal)``: The plane defined by one point and one normal vector,
          with the following format: ``array([Px,Py,Pz]), array([Nx,Ny,Nz])``

    .. deprecated:: 3.0.0
        Use :func:`compute_best_fitting_plane` instead.
    """
    warnings.warn(
        "Using 'best_fitting_plane' is deprecated. "
        "Please use 'compute_best_fitting_plane' instead",
        DeprecationWarning,
        stacklevel=2,
    )
    if equation:
        return compute_best_fitting_plane(points)
    else:
        return _compute_mean_and_normal(points)
